package com.demo;

public class IfElseIfControlStructure {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int clrval=2;
		if(clrval==1)
			System.out.println("Color Blue!");
		else if(clrval==2)
		System.out.println("Color Red!");
		else
			System.out.println("Color Green!");
	}

}
